  return (
    <div className="min-h-screen bg-[#081C3A] flex">
      <Sidebar user={user} currentView={currentView} setView={setView} onLogout={onLogout} />
      <main className="flex-1 ml-64 p-8 overflow-y-auto">
        {currentView === 'dashboard' && (
          <Dashboard 
            onAllocate={handleAllocate} 
            onViewPortfolio={() => setView('portfolio')}
            requests={requests}
          />
        )}
        {currentView === 'portfolio' && (
          <Portfolio onAllocate={handleAllocate} />
        )}
        {currentView === 'profile' && (
          <Profile user={user} onLogout={onLogout} onNavigateToAccreditation={() => setView('accreditation')} />
        )}
        {currentView === 'accreditation' && (
          <Accreditation user={user} accounts={[]} />
        )}

        {['distributions', 'documents'].includes(currentView) && (
          <div className="flex items-center justify-center h-full">
            <Card className="text-center p-20 max-w-lg border-white/5">
              <h2 className="text-2xl font-bold text-white uppercase mb-4">{currentView} Module</h2>
              <p className="text-[#8FAEDB] text-sm uppercase tracking-widest leading-relaxed">Infrastructure under maintenance. Your ledger data remains encrypted and secure.</p>
              <Button onClick={() => setView('dashboard')} variant="outline" className="mt-8">Return to Dashboard</Button>
            </Card>
          </div>
        )}
      </main>

      {selectedDeal && (
        <InvestmentModal 
          deal={selectedDeal} 
          onClose={() => setSelectedDeal(null)} 
          onSubmit={handleInvestmentSubmit}
        />
      )}

      {/* Support Orb */}
      <div className="fixed bottom-8 right-8 z-40">
        <button className="w-14 h-14 bg-[#2F80ED] rounded-full flex items-center justify-center text-white cyan-glow hover:scale-110 transition-all border border-white/10">
           <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
             <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"></path>
           </svg>
        </button>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>('LANDING');
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    window.scrollTo(0, 0);
  }, [appState]);

  const handleLoginSuccess = (userData: User) => {
    setUser(userData);
    if (userData.onboarded) {
      setAppState('PORTAL');
    } else {
      setAppState('ONBOARDING');
    }
  };

  const handleOnboardingComplete = () => {
    if (user) {
      setUser({ ...user, onboarded: true });
      setAppState('PORTAL');
    }
  };

  const handleLogout = () => {
    setUser(null);
    setAppState('LANDING');
  };

  if (appState === 'LANDING') return <LandingPage onStart={() => setAppState('AUTH')} />;
  if (appState === 'AUTH') return <Auth onSuccess={handleLoginSuccess} onBack={() => setAppState('LANDING')} />;
  if (appState === 'ONBOARDING' && user) return <Onboarding user={user} onComplete={handleOnboardingComplete} />;
  if (appState === 'PORTAL' && user) return <Portal user={user} onLogout={handleLogout} />;

  return null;
};

export default App;

import React from 'react';

// Added type prop to support standard button behaviors (submit, button, reset) and resolve type errors when used in forms
export const Button: React.FC<{
  children: React.ReactNode;
  variant?: 'primary' | 'outline' | 'ghost';
  className?: string;
  onClick?: () => void;
  disabled?: boolean;
  type?: 'button' | 'submit' | 'reset';
}> = ({ children, variant = 'primary', className = '', onClick, disabled, type = 'submit' }) => {
  const base = 'px-6 py-2.5 rounded font-semibold transition-all duration-200 disabled:opacity-50 disabled:cursor-not-allowed text-sm uppercase tracking-wider';
  const variants = {
    primary: 'bg-[#2F80ED] text-white hover:bg-[#1457B6] cyan-glow shadow-lg shadow-[#2F80ED]/20',
    outline: 'border border-[#2F80ED] text-[#2F80ED] hover:bg-[#2F80ED]/10',
    ghost: 'text-[#8FAEDB] hover:text-white hover:bg-white/5'
  };

  return (
    <button 
      type={type} 
      className={`${base} ${variants[variant]} ${className}`} 
      onClick={onClick} 
      disabled={disabled}
    >
      {children}
    </button>
  );
};

export const Badge: React.FC<{ children: React.ReactNode; variant?: 'success' | 'info' | 'warning' }> = ({ children, variant = 'info' }) => {
  const variants = {
    success: 'bg-[#00E0C6]/10 text-[#00E0C6] border-[#00E0C6]/30',
    info: 'bg-[#2F80ED]/10 text-[#2F80ED] border-[#2F80ED]/30',
    warning: 'bg-yellow-500/10 text-yellow-500 border-yellow-500/30'
  };

  return (
    <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-tight border ${variants[variant]}`}>
      {children}
    </span>
  );
};

export const Card: React.FC<{ children: React.ReactNode; className?: string }> = ({ children, className = '' }) => (
  <div className={`glass-panel p-6 rounded-xl ${className}`}>
    {children}
  </div>
);

